		&lt;tr&gt;
			&lt;td&gt;
			&lt;p&gt;प्रोपीलीन ग्लिसरॉल&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p&gt;&lt;img alt=&quot;Propylene Glycol Chemical, For ...&quot; class=&quot;YQ4gaf&quot; data-atf=&quot;8&quot; data-csiid=&quot;Mry-aPu2JI6UseMPyMbR4Qg_39&quot; height=&quot;182&quot; id=&quot;dimg_Mry-aPu2JI6UseMPyMbR4Qg_29&quot; src=&quot;//cdn.testbook.com/images/production/quesImages/qImage68bebc9fee12db081ed00c83.png&quot; style=&quot;color: rgb(33, 37, 41); object-position: center center;&quot; width=&quot;277&quot; /&gt;&lt;/p&gt;
